// ============================================================
// ENFORCE SANDBOX + FILTER ACTIVE CLIENTS
// NEVER routes to production unless environment='production'
// ============================================================

const clients = $input.all()
  .filter(item => String(item.json.active).toUpperCase() === 'TRUE')
  .map(item => {
    const cfg = item.json;
    const isProd = cfg.environment === 'production';

    const qbBaseUrl = isProd
      ? 'https://quickbooks.api.intuit.com'
      : 'https://sandbox-quickbooks.api.intuit.com';

    const qbPaymentLinkBase = isProd
      ? 'https://app.qbo.intuit.com'
      : 'https://sandbox.qbo.intuit.com';

    return {
      json: {
        ...cfg,
        qb_base_url: qbBaseUrl,
        qb_payment_link_base: qbPaymentLinkBase,
        effective_environment: cfg.environment || 'sandbox',
        qb_minor_version: parseInt(cfg.qb_minor_version || '73', 10)
      }
    };
  });

if (clients.length === 0) {
  throw new Error('No active clients found in Client_Master_Config. Check that active=TRUE for at least one row.');
}

console.log(`WF2 running for ${clients.length} active client(s): ${clients.map(c => c.json.client_name).join(', ')}`);
return clients;

const token = $input.first().json;
const expiresAt = new Date(Date.now() + (token.expires_in || 3600) * 1000).toISOString();

// Write fresh token back to OAuth sheet
const cfg = $('Loop: Process Each Client').item.json;

return [{
  json: {
    client_id: cfg.client_id,
    access_token: token.access_token,
    refresh_token: token.refresh_token || $('Get OAuth Credentials').first().json.refresh_token,
    expires_at: expiresAt,
    retrieved_at: new Date().toISOString()
  }
}];

// Merge client config with whichever token path was taken
const cfg = $('Loop: Process Each Client').item.json;

// Determine which token node ran
let token;
try {
  token = $('Store Fresh Token').first().json;
} catch (e) {
  // Token was fresh — use the value read from Get OAuth Credentials
  token = $('Get OAuth Credentials').first().json;
}

if (!token.access_token) {
  throw new Error(`OAuth token missing for client: ${cfg.client_name}`);
}

return [{
  json: {
    ...cfg,
    access_token: token.access_token,
    authorization_header: `Bearer ${token.access_token}`,
    token_expires_at: token.expires_at,
    token_retrieved_at: token.retrieved_at
  }
}];

// ============================================================
// EXTRACT + ENRICH INVOICE DATA
// Flattens QB invoice objects into reminder-ready records.
// Calculates days overdue, formats payment link.
// ============================================================

const cfg = $('Merge Config + Token').first().json;
const invoices = $input.first().json.QueryResponse?.Invoice || [];

const today = new Date();
today.setHours(0, 0, 0, 0);

const enriched = [];

for (const inv of invoices) {
  const dueDate = new Date(inv.DueDate);
  dueDate.setHours(0, 0, 0, 0);
  const daysOverdue = Math.floor((today - dueDate) / 86400000);

  // Skip invoices not yet overdue
  if (daysOverdue < 1) continue;

  const customerName = inv.CustomerRef?.name || 'Unknown Customer';
  const customerEmail = inv.BillEmail?.Address || '';
  const invoiceNum = inv.DocNumber || inv.Id;
  const balance = parseFloat(inv.Balance || 0);
  const totalAmt = parseFloat(inv.TotalAmt || 0);

  const paymentLink = `${cfg.qb_payment_link_base}/app/invoice?invoiceId=${inv.Id}`;

  enriched.push({
    json: {
      // Identifiers
      client_id: cfg.client_id,
      client_name: cfg.client_name,
      qb_invoice_id: inv.Id,
      invoice_num: invoiceNum,
      // Customer
      customer_name: customerName,
      customer_email: customerEmail,
      customer_id: inv.CustomerRef?.value || '',
      // Financials
      balance_due: balance,
      total_amount: totalAmt,
      currency: inv.CurrencyRef?.value || 'USD',
      // Dates
      due_date: inv.DueDate,
      days_overdue: daysOverdue,
      // Links
      payment_link: paymentLink,
      // Pass-through config for downstream nodes
      slack_ar_channel_id: cfg.slack_ar_channel_id,
      slack_dev_channel_id: cfg.slack_dev_channel_id,
      data_sheet_id: cfg.data_sheet_id,
      ar_reminder_log_gid: cfg.ar_reminder_log_gid,
      reminder_email_from: cfg.reminder_email_from,
      reminder_outlook_tenant_id: cfg.reminder_outlook_tenant_id,
      reminder_outlook_client_id: cfg.reminder_outlook_client_id,
      reminder_outlook_client_secret: cfg.reminder_outlook_client_secret
    }
  });
}

if (enriched.length === 0) {
  // All invoices are future-dated — treat as no-op
  throw new Error(`NO_OVERDUE_INVOICES:${cfg.client_name}`);
}

return enriched;

// ============================================================
// FILTER: PILOT CUSTOMERS ONLY
// Only send reminders to customers explicitly on the pilot list.
// ============================================================

const pilotItems = $('Load Pilot Customer List').all();
const pilotNames = new Set(
  pilotItems.map(i => (i.json.customer_name || '').trim().toLowerCase())
);

if (pilotNames.size === 0) {
  console.log('Pilot list is empty — no reminders will be sent this run.');
  return [];
}

const invoices = $input.all();
const filtered = invoices.filter(item => {
  const name = (item.json.customer_name || '').trim().toLowerCase();
  return pilotNames.has(name);
});

console.log(`Pilot filter: ${invoices.length} invoices → ${filtered.length} match pilot list`);
return filtered;

// ============================================================
// FILTER: REMOVE VIP EXEMPTIONS
// VIP customers never receive automated reminders.
// ============================================================

const vipItems = $('Load VIP Exemption List').all();
const vipNames = new Set(
  vipItems.map(i => (i.json.customer_name || '').trim().toLowerCase())
);

const invoices = $input.all();
const filtered = invoices.filter(item => {
  const name = (item.json.customer_name || '').trim().toLowerCase();
  return !vipNames.has(name);
});

console.log(`VIP filter: ${invoices.length} invoices → ${filtered.length} after removing ${invoices.length - filtered.length} VIP exemptions`);
return filtered;

// ============================================================
// BUILD REMINDER EMAIL BODY
// Outlook/Graph API requires HTML body.
// Personalizes by customer name, invoice number, days overdue.
// ============================================================

const items = $input.all();
const results = [];

for (const item of items) {
  const inv = item.json;

  const urgencyLine = inv.days_overdue > 30
    ? `<p style="color:#dc2626;font-weight:bold;">⚠ This invoice is now ${inv.days_overdue} days past due. Please remit payment at your earliest convenience to avoid service interruption.</p>`
    : `<p>This is a friendly reminder that the invoice below is ${inv.days_overdue} day${inv.days_overdue !== 1 ? 's' : ''} past due.</p>`;

  const htmlBody = `
<html><body style="font-family:Arial,sans-serif;color:#333;">
<p>Dear ${inv.customer_name},</p>
${urgencyLine}
<table style="border-collapse:collapse;margin:16px 0;">
  <tr><td style="padding:6px 12px;font-weight:bold;">Invoice #</td><td style="padding:6px 12px;">${inv.invoice_num}</td></tr>
  <tr style="background:#f5f5f5;"><td style="padding:6px 12px;font-weight:bold;">Amount Due</td><td style="padding:6px 12px;">$${inv.balance_due.toLocaleString('en-US', { minimumFractionDigits: 2 })}</td></tr>
  <tr><td style="padding:6px 12px;font-weight:bold;">Due Date</td><td style="padding:6px 12px;">${inv.due_date}</td></tr>
</table>
<p><a href="${inv.payment_link}" style="background:#1a56db;color:#fff;padding:10px 20px;text-decoration:none;border-radius:4px;display:inline-block;">Pay Now</a></p>
<p style="font-size:12px;color:#666;">If you have already remitted payment, please disregard this notice. Questions? Reply to this email.</p>
<p>Thank you,<br/>${inv.client_name}</p>
</body></html>`;

  results.push({
    json: {
      ...inv,
      email_subject: `Payment Reminder: Invoice #${inv.invoice_num} — $${inv.balance_due.toFixed(2)} Due`,
      email_html_body: htmlBody,
      email_to: inv.customer_email
    }
  });
}

return results;

// ============================================================
// BUILD SLACK AR AGING SUMMARY
// Parses QB AgedReceivableDetail report into Slack blocks.
// ============================================================

const cfg = $('Merge Config + Token').first().json;
const report = $input.first().json;

const today = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });

// QB aging report Row structure varies — parse Columns + Rows
const rows = report.Rows?.Row || [];
const totals = { current: 0, d1_30: 0, d31_60: 0, d61_90: 0, d91plus: 0, total: 0 };

// Sum bucket columns (QB report column order: Customer, Current, 1-30, 31-60, 61-90, 91+, Total)
for (const row of rows) {
  if (row.type !== 'Data') continue;
  const cols = row.ColData || [];
  if (cols.length < 7) continue;
  totals.current  += parseFloat(cols[1]?.value || 0);
  totals.d1_30    += parseFloat(cols[2]?.value || 0);
  totals.d31_60   += parseFloat(cols[3]?.value || 0);
  totals.d61_90   += parseFloat(cols[4]?.value || 0);
  totals.d91plus  += parseFloat(cols[5]?.value || 0);
  totals.total    += parseFloat(cols[6]?.value || 0);
}

const fmt = n => `$${n.toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 })}`;

const riskPct = totals.total > 0
  ? Math.round(((totals.d31_60 + totals.d61_90 + totals.d91plus) / totals.total) * 100)
  : 0;

const riskEmoji = riskPct > 40 ? '🔴' : riskPct > 20 ? '🟡' : '🟢';

return [{
  json: {
    client_name: cfg.client_name,
    slack_ar_channel_id: cfg.slack_ar_channel_id,
    slack_message: {
      channel: cfg.slack_ar_channel_id,
      text: `AR Aging Summary — ${cfg.client_name} — ${today}`,
      blocks: [
        {
          type: 'header',
          text: { type: 'plain_text', text: `📊 AR Aging — ${cfg.client_name}` }
        },
        {
          type: 'section',
          text: { type: 'mrkdwn', text: `*${today}* · LunarLogic AR Automation` }
        },
        { type: 'divider' },
        {
          type: 'section',
          fields: [
            { type: 'mrkdwn', text: `*Current:*\n${fmt(totals.current)}` },
            { type: 'mrkdwn', text: `*1–30 days:*\n${fmt(totals.d1_30)}` },
            { type: 'mrkdwn', text: `*31–60 days:*\n${fmt(totals.d31_60)}` },
            { type: 'mrkdwn', text: `*61–90 days:*\n${fmt(totals.d61_90)}` },
            { type: 'mrkdwn', text: `*90+ days:*\n${fmt(totals.d91plus)}` },
            { type: 'mrkdwn', text: `*Total AR:*\n*${fmt(totals.total)}*` }
          ]
        },
        {
          type: 'section',
          text: { type: 'mrkdwn', text: `${riskEmoji} *${riskPct}%* of AR is 31+ days past due` }
        }
      ]
    },
    totals
  }
}];

// Loop back to process next client.
// This node intentionally returns empty to allow the SplitInBatches
// node to advance to the next item.
return [];

// ============================================================
// ERROR: ANALYZE QB API FAILURE
// Captures error details and client context for routing.
// ============================================================

const error = $input.first().json.error || $input.first().json;
const cfg = $('Loop: Process Each Client').item?.json || {};

const statusCode = error.statusCode || error.httpCode || 0;
const message = error.message || JSON.stringify(error);

// Classify retryability
const isRetriable = statusCode === 0    // network error
  || statusCode === 429  // rate limit
  || statusCode === 503  // QB service unavailable
  || statusCode === 504; // gateway timeout

const retryCount = parseInt(cfg.retry_count || '0', 10);

return [{
  json: {
    client_id: cfg.client_id || 'unknown',
    client_name: cfg.client_name || 'Unknown Client',
    slack_dev_channel_id: cfg.slack_dev_channel_id || '',
    data_sheet_id: cfg.data_sheet_id || '',
    error_log_gid: cfg.error_log_gid || '',
    status_code: statusCode,
    error_message: message,
    is_retriable: isRetriable,
    retry_count: retryCount,
    failed_at: new Date().toISOString()
  }
}];

const item = $input.first().json;
const retryCount = (item.retry_count || 0) + 1;
const circuitBreakerTripped = retryCount >= 3;

return [{
  json: {
    ...item,
    retry_count: retryCount,
    circuit_breaker_tripped: circuitBreakerTripped
  }
}];

